You can use the following function to check if any of the numbers in the given array is a valid prime number:
```javascript
function isPrime(number) {
  for (let i = 2; i < number; i++) {
    if (number % i === 0) {
      return false;
    }
  }
  return number > 1;
}

function checkPrime(numbers) {
  for (let number of numbers) {
    if (isPrime(number)) {
      console.log(number);
      break;
    }
  }
}

// Usage example
